import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from 'react';
import type { ListItemBase, ListGroup } from '@o9ds/core';
import { filterItems, filterGroups } from '@o9ds/core';
import { useListNavigation } from '../../hooks/useListNavigation';
import { FormLabel } from '../FormLabel';
import O9Search from '../Search/Search';
import type { MenuSearchProp } from '../../types/menu-search';
import { normalizeSearch } from '../../types/menu-search';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ListboxOptionData extends ListItemBase {
  value: unknown;
}

export interface O9ListboxProps {
  items: ListboxOptionData[] | ListGroup<ListboxOptionData>[];
  value?: unknown | unknown[];
  defaultValue?: unknown | unknown[];
  label?: string;
  isMultiple?: boolean;
  /** Enable search with defaults (`true`) or pass a config object. */
  search?: MenuSearchProp;
  isLoading?: boolean;
  isDisabled?: boolean;
  isRequired?: boolean;
  emptyMessage?: string;
  hasGroupDividers?: boolean;
  size?: 'sm' | 'md' | 'lg';
  onChange?: (value: unknown | unknown[], option: ListboxOptionData) => void;
  onHighlight?: (value: unknown, option: ListboxOptionData) => void;
  onFilter?: (query: string, matchCount: number) => void;
  className?: string;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function isGrouped(
  items: ListboxOptionData[] | ListGroup<ListboxOptionData>[],
): items is ListGroup<ListboxOptionData>[] {
  return items.length > 0 && 'items' in items[0];
}

function flattenItems(
  items: ListboxOptionData[] | ListGroup<ListboxOptionData>[],
): ListboxOptionData[] {
  if (isGrouped(items)) return items.flatMap((g) => g.items);
  return items as ListboxOptionData[];
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9Listbox = forwardRef<HTMLDivElement, O9ListboxProps>(
  function O9Listbox(
    {
      items,
      value,
      defaultValue,
      label,
      isMultiple = false,
      search,
      isLoading = false,
      isDisabled = false,
      isRequired = false,
      emptyMessage = 'No options',
      hasGroupDividers = true,
      size = 'md',
      onChange,
      onHighlight,
      onFilter,
      className,
    },
    ref,
  ) {
    const uid = useId();
    const listId = `o9ds-listbox-${uid}`;
    const labelId = `${listId}-lbl`;
    const getOptionId = (index: number) => `${listId}-opt-${index}`;

    const searchCfg = useMemo(
      () => normalizeSearch(search, { shortcut: '/' }),
      [search],
    );

    const listRef = useRef<HTMLDivElement>(null);
    const searchWrapperRef = useRef<HTMLDivElement>(null);

    // ── Controlled / Uncontrolled value ───────────────────────────────
    const isValueControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState<unknown>(() =>
      defaultValue ?? (isMultiple ? [] : undefined),
    );
    const currentValue = isValueControlled ? value : internalValue;

    const isSelected = useCallback(
      (optionValue: unknown): boolean => {
        if (isMultiple) {
          const arr = Array.isArray(currentValue) ? currentValue : [];
          return arr.includes(optionValue);
        }
        return currentValue === optionValue;
      },
      [currentValue, isMultiple],
    );

    // ── Filter state ─────────────────────────────────────────────────
    const [query, setQuery] = useState('');

    const filteredItems = useMemo(() => {
      if (!searchCfg || !query) return items;
      if (isGrouped(items)) {
        return filterGroups(items, { query });
      }
      return filterItems(items as ListboxOptionData[], { query });
    }, [items, searchCfg, query]);

    const flatOptions = useMemo(
      () => flattenItems(filteredItems),
      [filteredItems],
    );

    const totalOptionCount = useMemo(() => flattenItems(items).length, [items]);

    useEffect(() => {
      if (searchCfg && query) {
        searchCfg.onFilter?.(query, flatOptions.length);
        onFilter?.(query, flatOptions.length);
      }
    }, [searchCfg, query, flatOptions.length, onFilter]);

    // ── Selection handler ────────────────────────────────────────────
    const handleSelect = useCallback(
      (option: ListboxOptionData) => {
        if (option.isDisabled) return;

        if (isMultiple) {
          const arr = Array.isArray(currentValue) ? [...currentValue] : [];
          const idx = arr.indexOf(option.value);
          if (idx >= 0) {
            arr.splice(idx, 1);
          } else {
            arr.push(option.value);
          }
          if (!isValueControlled) setInternalValue(arr);
          onChange?.(arr, option);
        } else {
          if (!isValueControlled) setInternalValue(option.value);
          onChange?.(option.value, option);
        }
      },
      [currentValue, isMultiple, isValueControlled, onChange],
    );

    // ── Scroll to index ──────────────────────────────────────────────
    const scrollToIndex = useCallback(
      (index: number) => {
        const optionEl = listRef.current?.querySelector(
          `[id="${getOptionId(index)}"]`,
        );
        optionEl?.scrollIntoView({ block: 'nearest' });
      },
      [getOptionId],
    );

    // ── List navigation ──────────────────────────────────────────────
    const handleItemSelect = useCallback(
      (item: ListItemBase, _index: number) => {
        handleSelect(item as ListboxOptionData);
      },
      [handleSelect],
    );

    const { activeIndex, setActiveIndex, handleKeyDown: navKeyDown } =
      useListNavigation({
        items: flatOptions,
        onSelect: handleItemSelect,
        wrap: true,
        enabled: !isDisabled && !isLoading,
        scrollToIndex,
      });

    // Fire onHighlight callback when active index changes
    useEffect(() => {
      if (activeIndex >= 0 && activeIndex < flatOptions.length) {
        const option = flatOptions[activeIndex];
        onHighlight?.(option.value, option);
      }
    }, [activeIndex, flatOptions, onHighlight]);

    // Reset active index when filtered items change
    useEffect(() => {
      const firstEnabled = flatOptions.findIndex((item) => !item.isDisabled);
      setActiveIndex(firstEnabled >= 0 ? firstEnabled : 0);
    }, [flatOptions, setActiveIndex]);

    // ── Keyboard handler ─────────────────────────────────────────────
    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent) => {
        if (isDisabled || isLoading) return;
        navKeyDown(e);
      },
      [isDisabled, isLoading, navKeyDown],
    );

    // ── Search handlers (O9Search callbacks) ────────────────────────
    const handleFilterSearch = useCallback(
      (value: string) => {
        setQuery(value);
        setActiveIndex(0);
      },
      [setActiveIndex],
    );

    const handleFilterClear = useCallback(() => {
      setQuery('');
      setActiveIndex(0);
      searchCfg?.onClear?.();
    }, [setActiveIndex, searchCfg]);

    const handleSearchWrapperKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLDivElement>) => {
        switch (e.key) {
          case 'ArrowDown':
          case 'ArrowUp':
          case 'Home':
          case 'End':
            e.preventDefault();
            navKeyDown(e);
            break;
          case 'Enter':
            e.preventDefault();
            if (activeIndex >= 0 && activeIndex < flatOptions.length) {
              const item = flatOptions[activeIndex];
              if (!item.isDisabled) handleSelect(item);
            }
            break;
        }
      },
      [navKeyDown, activeIndex, flatOptions, handleSelect],
    );

    // ── Item click handler ───────────────────────────────────────────
    const handleItemClick = useCallback(
      (option: ListboxOptionData, flatIndex: number) => {
        if (option.isDisabled || isLoading) return;
        setActiveIndex(flatIndex);
        handleSelect(option);
      },
      [isLoading, setActiveIndex, handleSelect],
    );

    // ── CSS classes ──────────────────────────────────────────────────
    const classes = [
      'o9ds-listbox',
      `o9ds-listbox--${size}`,
      isMultiple && 'o9ds-listbox--multiple',
      searchCfg && 'o9ds-listbox--searchable',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Option rendering ─────────────────────────────────────────────
    const renderOption = (item: ListboxOptionData, flatIndex: number) => {
      const isItemSelected = isSelected(item.value);
      const isHighlighted = flatIndex === activeIndex;
      const optClasses = [
        'o9ds-listbox__opt',
        item.isDisabled && 'is-disabled',
        isHighlighted && 'highlighted',
        isItemSelected && 'active',
      ]
        .filter(Boolean)
        .join(' ');

      return (
        <div
          key={item.id}
          id={getOptionId(flatIndex)}
          className={optClasses}
          role="option"
          aria-selected={isItemSelected}
          aria-disabled={item.isDisabled || undefined}
          onClick={() => handleItemClick(item, flatIndex)}
          onMouseEnter={() => {
            if (!item.isDisabled) setActiveIndex(flatIndex);
          }}
        >
          {item.icon && (
            <span
              className={`o9ds-listbox__opt__ico o9con o9con-${item.icon}`}
              aria-hidden="true"
            />
          )}
          <span className="o9ds-listbox__opt__lbl">{item.label}</span>
        </div>
      );
    };

    // ── Content rendering (flat vs grouped) ──────────────────────────
    const renderContent = () => {
      if (isLoading) {
        return (
          <div className="o9ds-listbox__skeleton">
            {[0, 1, 2, 3, 4].map((i) => (
              <div key={i} className="o9ds-listbox__skeleton-row">
                <div className="o9ds-listbox__skeleton-icon" />
                <div
                  className="o9ds-listbox__skeleton-text"
                  style={{ width: `${60 + ((i * 7) % 30)}%` }}
                />
              </div>
            ))}
          </div>
        );
      }

      if (flatOptions.length === 0) {
        return (
          <div className="o9ds-listbox__empty" role="status">
            {emptyMessage}
          </div>
        );
      }

      if (isGrouped(filteredItems)) {
        let flatIndex = 0;
        return (filteredItems as ListGroup<ListboxOptionData>[]).map(
          (group, groupIdx) => {
            const groupHdrId = `${listId}-grp-${groupIdx}`;
            return (
              <div key={group.id}>
                {groupIdx > 0 && hasGroupDividers && (
                  <hr className="o9ds-listbox__divider" role="separator" />
                )}
                <div
                  role="group"
                  aria-labelledby={group.label ? groupHdrId : undefined}
                  className="o9ds-listbox__grp"
                >
                  {group.label && (
                    <div id={groupHdrId} className="o9ds-listbox__grp-hdr">
                      {group.label}
                    </div>
                  )}
                  {group.items.map((item) => {
                    const node = renderOption(item, flatIndex);
                    flatIndex++;
                    return node;
                  })}
                </div>
              </div>
            );
          },
        );
      }

      return (filteredItems as ListboxOptionData[]).map((item, i) =>
        renderOption(item, i),
      );
    };

    // ── Highlighted option ID for aria-activedescendant ───────────────
    const highlightedOptionId =
      activeIndex >= 0 && activeIndex < flatOptions.length
        ? getOptionId(activeIndex)
        : undefined;

    // ── Render ────────────────────────────────────────────────────────
    return (
      <div ref={ref} className={classes}>
        {label && (
          <FormLabel
            htmlFor={listId}
            id={labelId}
            size={size === 'sm' ? 'sm' : 'lg'}
            isRequired={isRequired}
            isDisabled={isDisabled}
            className="o9ds-listbox__lbl"
          >
            {label}
          </FormLabel>
        )}

        {searchCfg && (
          <div
            ref={searchWrapperRef}
            className={[
              'o9ds-listbox__search',
              searchCfg.className,
            ].filter(Boolean).join(' ')}
            onKeyDown={handleSearchWrapperKeyDown}
          >
            <O9Search
              variant="filter"
              value={query}
              placeholder={searchCfg.placeholder}
              searchMode={searchCfg.searchMode}
              minChars={searchCfg.minChars}
              isClearable={searchCfg.isClearable}
              shortcut={searchCfg.shortcut}
              errorMsg={searchCfg.errorMsg}
              isInlineError
              counter={
                searchCfg.counter && query
                  ? { current: flatOptions.length, total: totalOptionCount }
                  : null
              }
              onSearch={handleFilterSearch}
              onClear={handleFilterClear}
              isDisabled={isDisabled}
              aria-label="Filter options"
            />
          </div>
        )}

        <div
          ref={listRef}
          id={listId}
          className="o9ds-listbox__list"
          role="listbox"
          tabIndex={isDisabled ? -1 : 0}
          aria-multiselectable={isMultiple || undefined}
          aria-activedescendant={highlightedOptionId}
          aria-busy={isLoading || undefined}
          aria-labelledby={label ? labelId : undefined}
          aria-disabled={isDisabled || undefined}
          aria-required={isRequired || undefined}
          onKeyDown={handleKeyDown}
        >
          {renderContent()}
        </div>
      </div>
    );
  },
);

export { O9Listbox };
export default O9Listbox;
